import { createContext, useContext, useState, ReactNode } from 'react';

// ── Mock credentials ──────────────────────────────────────────
const MOCK_EMAIL    = 'admin@123.com';
const MOCK_PASSWORD = '12345678';

// ── Types ─────────────────────────────────────────────────────
interface MockUser {
  id: string;
  email: string;
}

interface AuthContextType {
  user: MockUser | null;
  session: MockUser | null;
  loading: boolean;
  signIn: (email: string, password: string) => Promise<void>;
  signOut: () => Promise<void>;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export function AuthProvider({ children }: { children: ReactNode }) {
  const [user, setUser] = useState<MockUser | null>(null);
  const [loading] = useState(false);

  const signIn = async (email: string, password: string) => {
    if (email === MOCK_EMAIL && password === MOCK_PASSWORD) {
      setUser({ id: 'mock-admin-001', email });
    } else {
      throw new Error('Invalid email or password');
    }
  };

  const signOut = async () => {
    setUser(null);
  };

  const value = {
    user,
    session: user,
    loading,
    signIn,
    signOut,
  };

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
}

export function useAuth() {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
}

import { createContext, useContext, useEffect, useState, ReactNode } from 'react';

type Theme = 'light' | 'dark';

interface ThemeContextType {
  theme: Theme;
  toggleTheme: () => void;
}

const ThemeContext = createContext<ThemeContextType | undefined>(undefined);

export function ThemeProvider({ children }: { children: ReactNode }) {
  const [theme, setTheme] = useState<Theme>(() => {
    const stored = localStorage.getItem('theme');
    return (stored as Theme) || 'light';
  });

  useEffect(() => {
    localStorage.setItem('theme', theme);
    if (theme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [theme]);

  const toggleTheme = () => {
    setTheme((prev) => (prev === 'light' ? 'dark' : 'light'));
  };

  const value = {
    theme,
    toggleTheme,
  };

  return (
    <ThemeContext.Provider value={value}>{children}</ThemeContext.Provider>
  );
}

export function useTheme() {
  const context = useContext(ThemeContext);
  if (context === undefined) {
    throw new Error('useTheme must be used within a ThemeProvider');
  }
  return context;
}

import { useState } from 'react';
import { motion } from 'framer-motion';
import { LogIn, Mail, Lock } from 'lucide-react';
import { useTranslation } from 'react-i18next';
import { useAuth } from '../contexts/AuthContext';
import { Toast } from '../components/Toast';

export function Login() {
  const { t } = useTranslation();
  const { signIn } = useAuth();
  const [email, setEmail] = useState('admin@123.com');
  const [password, setPassword] = useState('12345678');
  const [loading, setLoading] = useState(false);
  const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' } | null>(null);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setToast(null);

    try {
      await signIn(email, password);
    } catch (error) {
      setToast({
        message: t('login.invalidCredentials'),
        type: 'error',
      });
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-50 to-blue-100 dark:from-gray-900 dark:to-gray-800 flex items-center justify-center p-4">
      {toast && (
        <Toast
          message={toast.message}
          type={toast.type}
          onClose={() => setToast(null)}
        />
      )}

      <motion.div
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.5 }}
        className="w-full max-w-md"
      >
        <div className="bg-white dark:bg-gray-800 rounded-2xl shadow-2xl p-8">
          <div className="text-center mb-8">
            <div className="inline-flex items-center justify-center w-16 h-16 bg-blue-100 dark:bg-blue-900 rounded-full mb-4">
              <LogIn className="w-8 h-8 text-blue-600 dark:text-blue-400" />
            </div>
            <h2 className="text-3xl font-bold text-gray-900 dark:text-white">
              {t('login.title')}
            </h2>
          </div>

          <form onSubmit={handleSubmit} className="space-y-6">
            <div>
              <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
                {t('login.email')}
              </label>
              <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                  <Mail className="h-5 w-5 text-gray-400" />
                </div>
                <input
                  type="email"
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  required
                  className="block w-full pl-10 pr-3 py-3 border border-gray-300 dark:border-gray-600 rounded-lg bg-white dark:bg-gray-700 text-gray-900 dark:text-white placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                  placeholder="admin@example.com"
                />
              </div>
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
                {t('login.password')}
              </label>
              <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                  <Lock className="h-5 w-5 text-gray-400" />
                </div>
                <input
                  type="password"
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  required
                  className="block w-full pl-10 pr-3 py-3 border border-gray-300 dark:border-gray-600 rounded-lg bg-white dark:bg-gray-700 text-gray-900 dark:text-white placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                  placeholder="••••••••"
                />
              </div>
            </div>

            <motion.button
              whileHover={{ scale: 1.02 }}
              whileTap={{ scale: 0.98 }}
              type="submit"
              disabled={loading}
              className="w-full bg-blue-600 hover:bg-blue-700 text-white font-semibold py-3 rounded-lg transition-colors disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2"
            >
              {loading ? t('login.loggingIn') : t('login.loginButton')}
            </motion.button>
          </form>
        </div>
      </motion.div>
    </div>
  );
}

import { useEffect, useState } from 'react';
import { motion } from 'framer-motion';
import { Calendar, Clock, Send } from 'lucide-react';
import { useTranslation } from 'react-i18next';
import { supabase, Area, WaterSchedule } from '../lib/supabase';
import { Toast } from '../components/Toast';

interface ScheduleWithArea extends WaterSchedule {
  areas?: Area;
}

export function Schedule() {
  const { t } = useTranslation();
  const [areas, setAreas] = useState<Area[]>([]);
  const [schedules, setSchedules] = useState<ScheduleWithArea[]>([]);
  const [selectedAreaId, setSelectedAreaId] = useState('');
  const [startTime, setStartTime] = useState('06:00');
  const [endTime, setEndTime] = useState('09:00');
  const [sending, setSending] = useState(false);
  const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' } | null>(null);

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    try {
      const [areasRes, schedulesRes] = await Promise.all([
        supabase.from('areas').select('*').order('name'),
        supabase
          .from('water_schedules')
          .select('*, areas(*)')
          .order('created_at', { ascending: false }),
      ]);

      if (areasRes.error) throw areasRes.error;
      if (schedulesRes.error) throw schedulesRes.error;

      setAreas(areasRes.data || []);
      setSchedules(schedulesRes.data || []);
      if (areasRes.data && areasRes.data.length > 0) {
        setSelectedAreaId(areasRes.data[0].id);
      }
    } catch (error) {
      console.error('Error loading data:', error);
      setToast({ message: 'Error loading data', type: 'error' });
    }
  };

  const convertTo12Hour = (time24: string): string => {
    const [hours, minutes] = time24.split(':');
    const hour = parseInt(hours);
    const ampm = hour >= 12 ? 'PM' : 'AM';
    const hour12 = hour % 12 || 12;
    return `${hour12.toString().padStart(2, '0')}:${minutes} ${ampm}`;
  };

  const handleSetSchedule = async () => {
    if (!selectedAreaId || !startTime || !endTime) {
      setToast({ message: 'Please fill all fields', type: 'error' });
      return;
    }

    setSending(true);
    try {
      const start12 = convertTo12Hour(startTime);
      const end12 = convertTo12Hour(endTime);

      const { error: scheduleError } = await supabase
        .from('water_schedules')
        .insert([
          {
            area_id: selectedAreaId,
            start_time: start12,
            end_time: end12,
            is_active: true,
          },
        ]);

      if (scheduleError) throw scheduleError;

      const apiUrl = `${import.meta.env.VITE_SUPABASE_URL}/functions/v1/send-sms`;
      const headers = {
        Authorization: `Bearer ${import.meta.env.VITE_SUPABASE_ANON_KEY}`,
        'Content-Type': 'application/json',
      };

      const response = await fetch(apiUrl, {
        method: 'POST',
        headers,
        body: JSON.stringify({
          areaId: selectedAreaId,
          startTime: start12,
          endTime: end12,
        }),
      });

      const result = await response.json();

      if (!response.ok) {
        throw new Error(result.error || 'Failed to send SMS');
      }

      setToast({
        message: `Schedule set! SMS sent to ${result.sentCount} users`,
        type: 'success',
      });

      loadData();
    } catch (error: any) {
      console.error('Error setting schedule:', error);
      setToast({ message: error.message || 'Error setting schedule', type: 'error' });
    } finally {
      setSending(false);
    }
  };

  return (
    <div className="space-y-6">
      {toast && (
        <Toast
          message={toast.message}
          type={toast.type}
          onClose={() => setToast(null)}
        />
      )}

      <h1 className="text-3xl font-bold text-gray-900 dark:text-white">
        {t('schedule.title')}
      </h1>

      <div className="bg-white dark:bg-gray-800 rounded-xl shadow-lg border border-gray-200 dark:border-gray-700 p-6">
        <div className="space-y-6">
          <div>
            <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
              {t('schedule.selectArea')}
            </label>
            <select
              value={selectedAreaId}
              onChange={(e) => setSelectedAreaId(e.target.value)}
              className="w-full px-4 py-3 border border-gray-300 dark:border-gray-600 rounded-lg bg-white dark:bg-gray-700 text-gray-900 dark:text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
            >
              {areas.map((area) => (
                <option key={area.id} value={area.id}>
                  {area.name}
                </option>
              ))}
            </select>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div>
              <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
                <Clock className="w-4 h-4 inline mr-1" />
                {t('schedule.startTime')}
              </label>
              <input
                type="time"
                value={startTime}
                onChange={(e) => setStartTime(e.target.value)}
                className="w-full px-4 py-3 border border-gray-300 dark:border-gray-600 rounded-lg bg-white dark:bg-gray-700 text-gray-900 dark:text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
                <Clock className="w-4 h-4 inline mr-1" />
                {t('schedule.endTime')}
              </label>
              <input
                type="time"
                value={endTime}
                onChange={(e) => setEndTime(e.target.value)}
                className="w-full px-4 py-3 border border-gray-300 dark:border-gray-600 rounded-lg bg-white dark:bg-gray-700 text-gray-900 dark:text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
              />
            </div>
          </div>

          <motion.button
            whileHover={{ scale: 1.02 }}
            whileTap={{ scale: 0.98 }}
            onClick={handleSetSchedule}
            disabled={sending}
            className="w-full flex items-center justify-center gap-2 px-6 py-3 bg-blue-600 hover:bg-blue-700 text-white rounded-lg font-semibold transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
          >
            <Send className="w-5 h-5" />
            {sending ? t('schedule.sendingSMS') : t('schedule.setSchedule')}
          </motion.button>
        </div>
      </div>

      <div className="bg-white dark:bg-gray-800 rounded-xl shadow-lg border border-gray-200 dark:border-gray-700">
        <div className="p-6 border-b border-gray-200 dark:border-gray-700">
          <h2 className="text-xl font-semibold text-gray-900 dark:text-white flex items-center gap-2">
            <Calendar className="w-5 h-5" />
            {t('schedule.currentSchedules')}
          </h2>
        </div>
        <div className="p-6">
          {schedules.length === 0 ? (
            <p className="text-center text-gray-500 dark:text-gray-400 py-8">
              {t('schedule.noSchedules')}
            </p>
          ) : (
            <div className="space-y-4">
              {schedules.map((schedule) => (
                <motion.div
                  key={schedule.id}
                  initial={{ opacity: 0, y: 10 }}
                  animate={{ opacity: 1, y: 0 }}
                  className="flex items-center justify-between p-4 bg-gray-50 dark:bg-gray-700 rounded-lg"
                >
                  <div>
                    <h3 className="font-semibold text-gray-900 dark:text-white">
                      {schedule.areas?.name}
                    </h3>
                    <p className="text-sm text-gray-600 dark:text-gray-400">
                      {schedule.start_time} - {schedule.end_time}
                    </p>
                  </div>
                  <span
                    className={`px-3 py-1 rounded-full text-sm font-medium ${
                      schedule.is_active
                        ? 'bg-green-100 dark:bg-green-900 text-green-800 dark:text-green-200'
                        : 'bg-gray-200 dark:bg-gray-600 text-gray-800 dark:text-gray-200'
                    }`}
                  >
                    {schedule.is_active ? t('schedule.active') : t('schedule.inactive')}
                  </span>
                </motion.div>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

import { useEffect, useState, useRef } from 'react';
import { motion } from 'framer-motion';
import { Plus, CreditCard as Edit2, Trash2, Save, X, Upload } from 'lucide-react';
import { useTranslation } from 'react-i18next';
import Papa from 'papaparse';
import { supabase, Area, DistributionUser } from '../lib/supabase';
import { Modal } from '../components/Modal';
import { Toast } from '../components/Toast';

interface UserWithArea extends DistributionUser {
  areas?: Area;
}

export function Users() {
  const { t } = useTranslation();
  const [users, setUsers] = useState<UserWithArea[]>([]);
  const [areas, setAreas] = useState<Area[]>([]);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [showCSVModal, setShowCSVModal] = useState(false);
  const [editingUser, setEditingUser] = useState<DistributionUser | null>(null);
  const [userName, setUserName] = useState('');
  const [userPhone, setUserPhone] = useState('');
  const [selectedAreaId, setSelectedAreaId] = useState('');
  const [csvData, setCSVData] = useState<any[]>([]);
  const [importing, setImporting] = useState(false);
  const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' } | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    try {
      const [usersRes, areasRes] = await Promise.all([
        supabase
          .from('distribution_users')
          .select('*, areas(*)')
          .order('created_at', { ascending: false }),
        supabase.from('areas').select('*').order('name'),
      ]);

      if (usersRes.error) throw usersRes.error;
      if (areasRes.error) throw areasRes.error;

      setUsers(usersRes.data || []);
      setAreas(areasRes.data || []);
    } catch (error) {
      console.error('Error loading data:', error);
      setToast({ message: 'Error loading data', type: 'error' });
    } finally {
      setLoading(false);
    }
  };

  const handleAdd = () => {
    setEditingUser(null);
    setUserName('');
    setUserPhone('');
    setSelectedAreaId(areas.length > 0 ? areas[0].id : '');
    setShowModal(true);
  };

  const handleEdit = (user: UserWithArea) => {
    setEditingUser(user);
    setUserName(user.name);
    setUserPhone(user.phone);
    setSelectedAreaId(user.area_id);
    setShowModal(true);
  };

  const handleSave = async () => {
    if (!userName.trim() || !userPhone.trim() || !selectedAreaId) {
      setToast({ message: 'All fields are required', type: 'error' });
      return;
    }

    try {
      if (editingUser) {
        const { error } = await supabase
          .from('distribution_users')
          .update({ name: userName, phone: userPhone, area_id: selectedAreaId })
          .eq('id', editingUser.id);

        if (error) throw error;
        setToast({ message: 'User updated successfully', type: 'success' });
      } else {
        const { error } = await supabase
          .from('distribution_users')
          .insert([{ name: userName, phone: userPhone, area_id: selectedAreaId }]);

        if (error) throw error;
        setToast({ message: 'User added successfully', type: 'success' });
      }

      setShowModal(false);
      loadData();
    } catch (error) {
      console.error('Error saving user:', error);
      setToast({ message: 'Error saving user', type: 'error' });
    }
  };

  const handleDelete = async (user: DistributionUser) => {
    if (!confirm(t('users.deleteConfirm'))) return;

    try {
      const { error } = await supabase
        .from('distribution_users')
        .delete()
        .eq('id', user.id);

      if (error) throw error;
      setToast({ message: 'User deleted successfully', type: 'success' });
      loadData();
    } catch (error) {
      console.error('Error deleting user:', error);
      setToast({ message: 'Error deleting user', type: 'error' });
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    Papa.parse(file, {
      header: true,
      skipEmptyLines: true,
      complete: (results) => {
        setCSVData(results.data);
        setShowCSVModal(true);
      },
      error: (error) => {
        setToast({ message: `CSV parsing error: ${error.message}`, type: 'error' });
      },
    });
  };

  const handleImportCSV = async () => {
    if (csvData.length === 0) return;

    setImporting(true);
    try {
      const usersToImport = csvData.map((row) => {
        const areaName = row.area || row.Area;
        const area = areas.find(
          (a) => a.name.toLowerCase() === areaName?.toLowerCase()
        );

        return {
          name: row.name || row.Name,
          phone: row.phone || row.Phone,
          area_id: area?.id || areas[0]?.id,
        };
      });

      const { error } = await supabase
        .from('distribution_users')
        .insert(usersToImport);

      if (error) throw error;

      setToast({
        message: `Successfully imported ${usersToImport.length} users`,
        type: 'success',
      });
      setShowCSVModal(false);
      setCSVData([]);
      loadData();
    } catch (error) {
      console.error('Error importing users:', error);
      setToast({ message: 'Error importing users', type: 'error' });
    } finally {
      setImporting(false);
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center h-full">
        <div className="text-gray-500 dark:text-gray-400">{t('common.loading')}</div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {toast && (
        <Toast
          message={toast.message}
          type={toast.type}
          onClose={() => setToast(null)}
        />
      )}

      <div className="flex items-center justify-between">
        <h1 className="text-3xl font-bold text-gray-900 dark:text-white">
          {t('users.title')}
        </h1>
        <div className="flex gap-3">
          <input
            ref={fileInputRef}
            type="file"
            accept=".csv"
            onChange={handleFileChange}
            className="hidden"
          />
          <motion.button
            whileHover={{ scale: 1.05 }}
            whileTap={{ scale: 0.95 }}
            onClick={() => fileInputRef.current?.click()}
            className="flex items-center gap-2 px-4 py-2 bg-green-600 hover:bg-green-700 text-white rounded-lg font-medium transition-colors"
          >
            <Upload className="w-5 h-5" />
            {t('users.uploadCSV')}
          </motion.button>
          <motion.button
            whileHover={{ scale: 1.05 }}
            whileTap={{ scale: 0.95 }}
            onClick={handleAdd}
            className="flex items-center gap-2 px-4 py-2 bg-blue-600 hover:bg-blue-700 text-white rounded-lg font-medium transition-colors"
          >
            <Plus className="w-5 h-5" />
            {t('users.addUser')}
          </motion.button>
        </div>
      </div>

      <div className="bg-white dark:bg-gray-800 rounded-xl shadow-lg border border-gray-200 dark:border-gray-700">
        {users.length === 0 ? (
          <div className="p-12 text-center">
            <p className="text-gray-500 dark:text-gray-400">
              {t('users.noUsers')}
            </p>
          </div>
        ) : (
          <div className="overflow-x-auto">
            <table className="w-full">
              <thead className="bg-gray-50 dark:bg-gray-900">
                <tr>
                  <th className="text-left py-4 px-6 text-sm font-semibold text-gray-700 dark:text-gray-300">
                    {t('users.name')}
                  </th>
                  <th className="text-left py-4 px-6 text-sm font-semibold text-gray-700 dark:text-gray-300">
                    {t('users.phone')}
                  </th>
                  <th className="text-left py-4 px-6 text-sm font-semibold text-gray-700 dark:text-gray-300">
                    {t('users.area')}
                  </th>
                  <th className="text-right py-4 px-6 text-sm font-semibold text-gray-700 dark:text-gray-300">
                    {t('users.actions')}
                  </th>
                </tr>
              </thead>
              <tbody>
                {users.map((user) => (
                  <motion.tr
                    key={user.id}
                    initial={{ opacity: 0 }}
                    animate={{ opacity: 1 }}
                    className="border-t border-gray-200 dark:border-gray-700 hover:bg-gray-50 dark:hover:bg-gray-700 transition-colors"
                  >
                    <td className="py-4 px-6 text-gray-900 dark:text-white">
                      {user.name}
                    </td>
                    <td className="py-4 px-6 text-gray-900 dark:text-white">
                      {user.phone}
                    </td>
                    <td className="py-4 px-6 text-gray-900 dark:text-white">
                      {user.areas?.name || 'N/A'}
                    </td>
                    <td className="py-4 px-6">
                      <div className="flex items-center justify-end gap-2">
                        <motion.button
                          whileHover={{ scale: 1.1 }}
                          whileTap={{ scale: 0.9 }}
                          onClick={() => handleEdit(user)}
                          className="p-2 text-blue-600 dark:text-blue-400 hover:bg-blue-50 dark:hover:bg-blue-900 rounded-lg transition-colors"
                        >
                          <Edit2 className="w-4 h-4" />
                        </motion.button>
                        <motion.button
                          whileHover={{ scale: 1.1 }}
                          whileTap={{ scale: 0.9 }}
                          onClick={() => handleDelete(user)}
                          className="p-2 text-red-600 dark:text-red-400 hover:bg-red-50 dark:hover:bg-red-900 rounded-lg transition-colors"
                        >
                          <Trash2 className="w-4 h-4" />
                        </motion.button>
                      </div>
                    </td>
                  </motion.tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>

      <Modal
        isOpen={showModal}
        onClose={() => setShowModal(false)}
        title={editingUser ? t('users.edit') : t('users.addUser')}
      >
        <div className="space-y-4">
          <div>
            <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
              {t('users.name')}
            </label>
            <input
              type="text"
              value={userName}
              onChange={(e) => setUserName(e.target.value)}
              className="w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-lg bg-white dark:bg-gray-700 text-gray-900 dark:text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
            />
          </div>
          <div>
            <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
              {t('users.phone')}
            </label>
            <input
              type="tel"
              value={userPhone}
              onChange={(e) => setUserPhone(e.target.value)}
              className="w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-lg bg-white dark:bg-gray-700 text-gray-900 dark:text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
            />
          </div>
          <div>
            <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
              {t('users.area')}
            </label>
            <select
              value={selectedAreaId}
              onChange={(e) => setSelectedAreaId(e.target.value)}
              className="w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-lg bg-white dark:bg-gray-700 text-gray-900 dark:text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
            >
              {areas.map((area) => (
                <option key={area.id} value={area.id}>
                  {area.name}
                </option>
              ))}
            </select>
          </div>
          <div className="flex gap-3 justify-end">
            <motion.button
              whileHover={{ scale: 1.05 }}
              whileTap={{ scale: 0.95 }}
              onClick={() => setShowModal(false)}
              className="px-4 py-2 text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-lg transition-colors flex items-center gap-2"
            >
              <X className="w-4 h-4" />
              {t('users.cancel')}
            </motion.button>
            <motion.button
              whileHover={{ scale: 1.05 }}
              whileTap={{ scale: 0.95 }}
              onClick={handleSave}
              className="px-4 py-2 bg-blue-600 hover:bg-blue-700 text-white rounded-lg transition-colors flex items-center gap-2"
            >
              <Save className="w-4 h-4" />
              {t('users.save')}
            </motion.button>
          </div>
        </div>
      </Modal>

      <Modal
        isOpen={showCSVModal}
        onClose={() => setShowCSVModal(false)}
        title={t('users.preview')}
      >
        <div className="space-y-4">
          <p className="text-sm text-gray-600 dark:text-gray-400">
            {t('users.csvFormat')}
          </p>
          {csvData.length > 0 && (
            <div className="max-h-64 overflow-y-auto border border-gray-300 dark:border-gray-600 rounded-lg">
              <table className="w-full text-sm">
                <thead className="bg-gray-50 dark:bg-gray-900 sticky top-0">
                  <tr>
                    <th className="py-2 px-3 text-left text-gray-700 dark:text-gray-300">Name</th>
                    <th className="py-2 px-3 text-left text-gray-700 dark:text-gray-300">Phone</th>
                    <th className="py-2 px-3 text-left text-gray-700 dark:text-gray-300">Area</th>
                  </tr>
                </thead>
                <tbody>
                  {csvData.slice(0, 10).map((row, index) => (
                    <tr key={index} className="border-t border-gray-200 dark:border-gray-700">
                      <td className="py-2 px-3 text-gray-900 dark:text-white">
                        {row.name || row.Name}
                      </td>
                      <td className="py-2 px-3 text-gray-900 dark:text-white">
                        {row.phone || row.Phone}
                      </td>
                      <td className="py-2 px-3 text-gray-900 dark:text-white">
                        {row.area || row.Area}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
          <p className="text-sm text-gray-600 dark:text-gray-400">
            Total: {csvData.length} users
          </p>
          <div className="flex gap-3 justify-end">
            <motion.button
              whileHover={{ scale: 1.05 }}
              whileTap={{ scale: 0.95 }}
              onClick={() => setShowCSVModal(false)}
              className="px-4 py-2 text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-lg transition-colors"
            >
              {t('users.cancel')}
            </motion.button>
            <motion.button
              whileHover={{ scale: 1.05 }}
              whileTap={{ scale: 0.95 }}
              onClick={handleImportCSV}
              disabled={importing}
              className="px-4 py-2 bg-green-600 hover:bg-green-700 text-white rounded-lg transition-colors disabled:opacity-50"
            >
              {importing ? t('users.importing') : t('users.upload')}
            </motion.button>
          </div>
        </div>
      </Modal>
    </div>
  );
}
